import React, {useState} from "react";

function VideoCard({videoUrl, title, description, h, w}) {

  const [modal, setModal] = useState(false);
  const [videoLoading, setVideoLoading] = useState(true);

  function openModal(){
    setModal(!modal);
  };

  return (
  <div
    onClick={openModal}
    className="">
      {modal ? (
          <section className="">
            <div className="">
              <div className="" modal={modal}>
                <button
                  className=""
                  onClick={setModal}
                >X</button>
                <div className="">
                  {description}
                </div>
              </div>
            </div>
          </section>
        ) : null}
    </div>
  );
}

export default VideoCard;
